### Step 1: Define the Error Handling Middleware

We'll create a middleware function to handle errors and format them according to the specified structure.

```javascript
const express = require('express');
const app = express();
app.use(express.json());

// Error handling middleware
function errorHandler(err, req, res, next) {
    const requestId = req.headers['x-request-id'] || 'req_unknown'; // Assuming request ID is passed in headers
    const timestamp = new Date().toISOString();
    const service = 'order_service'; // Name of the service

    let response;

    if (err.isClientError) {
        // Client errors (4xx)
        response = {
            error: {
                code: err.code,
                message: err.message,
                request_id: requestId,
                details: err.details || []
            }
        };
        console.log(JSON.stringify({ level: 'error', message: err.message, request_id: requestId, timestamp, service, error: err }));
        return res.status(err.statusCode).json(response);
    } else {
        // Server errors (5xx)
        response = {
            error: {
                code: 'SERVER_ERROR',
                message: 'An unexpected error occurred. Please try again later.',
                request_id: requestId,
                details: []
            }
        };
